SELECT player_name
FROM Player
WHERE strftime('%Y', 'now') - strftime('%Y', birthday) >= 35;

SELECT player_name
FROM Player
WHERE strftime('%Y', 'now') - strftime('%Y', birthday) >= 35;

SELECT player_name
FROM Player
WHERE (strftime('%Y', '2023-12-31') - strftime('%Y', birthday)) - (strftime('%m-%d', '2023-12-31') < strftime('%m-%d', birthday)) >= 35;

SELECT player_name
FROM Player
WHERE strftime('%Y', 'now') - strftime('%Y', birthday) >= 35;

SELECT player_name
FROM Player
WHERE CAST((julianday('now') - julianday(birthday)) / 365.25 AS INTEGER) >= 35;
